const createItem = $items("Create Instance", 0, 0)[0]?.json || {};
const connectItem = items[0]?.json || {};
return [{
  json: {
    instance: createItem.instance?.instanceName || createItem.instanceName || connectItem.instance?.instanceName || null,
    status: connectItem.instance?.status || connectItem.instance?.state || createItem.instance?.status || 'desconhecido',
    pairingCode: connectItem.qrcode?.pairingCode || connectItem.pairingCode || null,
    base64: connectItem.qrcode?.base64 || connectItem.base64 || null,
    message: connectItem.message || null
  }
}];

const results = items[0].json.results || []
const cfg = {
  maxPrice: 400,
  minDiscountPct: 10
}
const store = getWorkflowStaticData('global')
if (!store.seen) {
  store.seen = []
}
const fresh = []
for (const product of results) {
  const price = product.price
  const original = product.original_price || price
  const discount = original > price ? (1 - price / original) * 100 : 0
  const wasSeen = store.seen.includes(product.id)
  if (!wasSeen && price <= cfg.maxPrice && discount >= cfg.minDiscountPct) {
    fresh.push({
      id: product.id,
      title: product.title,
      price: price,
      original_price: original,
      discount_pct: Number(discount.toFixed(1)),
      permalink: product.permalink,
      thumbnail: product.thumbnail,
      shipping: product.shipping?.free_shipping ? 'Frete grátis' : 'Frete calculado',
      seller_level: product.seller?.seller_reputation?.level_id || ''
    })
  }
}
if (fresh.length === 0) {
  return []
}
store.seen = [...fresh.map(f => f.id), ...store.seen].slice(0, 50)
return fresh.map(f => ({ json: f }))
